    {"name": "Assassin","type":"humanoid","size":"medium","alignment":"any non-good","cr":8,"xp":3900,"ac":15,"ac_type":"studded leather","hp":"78 (12d8+24)","hp_avg":78,"speed":"30 ft.","str":11,"dex":16,"con":14,"int":13,"wis":11,"cha":10,"skills":"Acrobatics +6, Deception +3, Perception +3, Stealth +9","saves":"Dex +6, Int +4","damage_resistances":"poison","senses":"passive Perception 13","languages":"Thieves' cant plus any two languages","environment":["urban"],"traits":[{"name":"Assassinate","desc":"During its first turn, the assassin has advantage on attack rolls against any creature that hasn't taken a turn. Any hit the assassin scores against a surprised creature is a critical hit."},{"name":"Evasion","desc":"If the assassin is subjected to an effect that allows a Dexterity saving throw to take only half damage, the assassin instead takes no damage if it succeeds on the saving throw, and only half damage if it fails."},{"name":"Sneak Attack","desc":"Once per turn, the assassin deals an extra 14 (4d6) damage when it hits a target with a weapon attack and has advantage on the attack roll."}],"actions":[{"name":"Multiattack","desc":"The assassin makes two shortsword attacks."},{"name":"Shortsword","desc":"Melee Weapon Attack: +6 to hit, reach 5 ft., one target. Hit: 6 (1d6 + 3) piercing damage, and the target must make a DC 15 Constitution saving throw, taking 24 (7d6) poison damage on a failed save, or half as much damage on a successful one."},{"name":"Light Crossbow","desc":"Ranged Weapon Attack: +6 to hit, range 80/320 ft., one target. Hit: 7 (1d8 + 3) piercing damage."}],"legendary_actions":[]},
