    {"name": "Wraith","type":"undead","size":"medium","alignment":"neutral evil","cr":5,"xp":1800,"ac":13,"ac_type":None,"hp":"67 (9d8+27)","hp_avg":67,"speed":"0 ft., fly 60 ft. (hover)","str":6,"dex":16,"con":16,"int":12,"wis":14,"cha":15,"skills":None,"saves":None,"damage_resistances":"acid, cold, fire, lightning, thunder; bludgeoning, piercing, and slashing from nonmagical attacks not made with silvered weapons","damage_immunities":"necrotic, poison","condition_immunities":"charmed, exhaustion, grappled, paralyzed, petrified, poisoned, prone, restrained","senses":"darkvision 60 ft., passive Perception 12","languages":"the languages it knew in life","environment":["underdark","urban"],"traits":[{"name":"Incorporeal Movement","desc":"The wraith can move through other creatures and objects as if they were difficult terrain."},{"name":"Sunlight Sensitivity","desc":"While in sunlight, the wraith has disadvantage on attack rolls, as well as on Wisdom (Perception) checks that rely on sight."}],"actions":[{"name":"Life Drain","desc":"Melee Weapon Attack: +6 to hit, reach 5 ft., one creature. Hit: 21 (4d8 + 3) necrotic damage. The target must succeed on a DC 14 Constitution saving throw or its hit point maximum is reduced by an amount equal to the damage taken."},{"name":"Create Specter","desc":"The wraith targets a humanoid within 10 ft. of it that has been dead for no longer than 1 minute and died violently. The target's spirit rises as a specter under the wraith's control."}],"legendary_actions":[]},
