    {"name": "Ghost","type":"undead","size":"medium","alignment":"any","cr":4,"xp":1100,"ac":11,"ac_type":None,"hp":"45 (10d8)","hp_avg":45,"speed":"0 ft., fly 40 ft. (hover)","str":7,"dex":13,"con":10,"int":10,"wis":12,"cha":17,"skills":None,"saves":None,"damage_resistances":"acid, fire, lightning, thunder; bludgeoning, piercing, and slashing from nonmagical attacks","damage_immunities":"cold, necrotic, poison","condition_immunities":"charmed, exhaustion, frightened, grappled, paralyzed, petrified, poisoned, prone, restrained","senses":"darkvision 60 ft., passive Perception 11","languages":"any languages it knew in life","environment":["underdark","urban"],"traits":[{"name":"Ethereal Sight","desc":"The ghost can see 60 ft. into the Ethereal Plane when it is on the Material Plane, and vice versa."},{"name":"Incorporeal Movement","desc":"The ghost can move through other creatures and objects as if they were difficult terrain."}],"actions":[{"name":"Withering Touch","desc":"Melee Weapon Attack: +5 to hit, reach 5 ft., one target. Hit: 17 (4d6 + 3) necrotic damage."},{"name":"Etherealness","desc":"The ghost enters the Ethereal Plane from the Material Plane, or vice versa."},{"name":"Horrifying Visage","desc":"Each non-undead creature within 60 ft. of the ghost that can see it must succeed on a DC 13 Wisdom saving throw or be frightened for 1 minute."},{"name":"Possession (Recharge 6)","desc":"One humanoid that the ghost can see within 5 ft. of it must succeed on a DC 13 Charisma saving throw or be possessed by the ghost."}],"legendary_actions":[]},
    {"name": "Mummy","type":"undead","size":"medium","alignment":"lawful evil","cr":3,"xp":700,"ac":11,"ac_type":"natural armor","hp":"58 (9d8+18)","hp_avg":58,"speed":"20 ft.","str":16,"dex":8,"con":15,"int":6,"wis":10,"cha":12,"skills":None,"saves":"Wis +2","damage_vulnerabilities":"fire","damage_resistances":"bludgeoning, piercing, and slashing from nonmagical attacks","damage_immunities":"necrotic, poison","condition_immunities":"charmed, exhaustion, frightened, paralyzed, poisoned","senses":"darkvision 60 ft., passive Perception 10","languages":"the languages it knew in life","environment":["desert","underdark"],"traits":[],"actions":[{"name":"Multiattack","desc":"The mummy can use its Dreadful Glare and makes one attack with its rotting fist."},{"name":"Rotting Fist","desc":"Melee Weapon Attack: +5 to hit, reach 5 ft., one target. Hit: 10 (2d6 + 3) bludgeoning damage plus 10 (3d6) necrotic damage. If the target is a creature, it must succeed on a DC 12 Constitution saving throw or be cursed with mummy rot."},{"name":"Dreadful Glare","desc":"The mummy targets one creature it can see within 60 ft. of it. If the target can see the mummy, it must succeed on a DC 11 Wisdom saving throw against this magic or become frightened until the end of the mummy's next turn."}],"legendary_actions":[]},
    {"name": "Banshee","type":"undead","size":"medium","alignment":"chaotic evil","cr":4,"xp":1100,"ac":12,"ac_type":None,"hp":"58 (13d8)","hp_avg":58,"speed":"0 ft., fly 40 ft. (hover)","str":1,"dex":14,"con":10,"int":12,"wis":11,"cha":17,"skills":None,"saves":"Wis +2, Cha +5","damage_resistances":"acid, fire, lightning, thunder; bludgeoning, piercing, and slashing from nonmagical attacks","damage_immunities":"cold, necrotic, poison","condition_immunities":"charmed, exhaustion, frightened, grappled, paralyzed, petrified, poisoned, prone, restrained","senses":"darkvision 60 ft., passive Perception 10","languages":"Common, Elvish","environment":["forest","swamp","urban"],"traits":[{"name":"Detect Life","desc":"The banshee can magically sense the presence of creatures up to 5 miles away."},{"name":"Incorporeal Movement","desc":"The banshee can move through other creatures and objects as if they were difficult terrain."}],"actions":[{"name":"Corrupting Touch","desc":"Melee Spell Attack: +4 to hit, reach 5 ft., one target. Hit: 12 (3d6 + 2) necrotic damage."},{"name":"Horrifying Visage","desc":"Each non-undead creature within 60 ft. of the banshee that can see it must succeed on a DC 13 Wisdom saving throw or be frightened for 1 minute."},{"name":"Wail (1/Day)","desc":"The banshee releases a mournful wail. All creatures within 30 ft. that can hear must make a DC 13 Constitution saving throw. On a failure, a creature drops to 0 hit points. On a success, a creature takes 10 (3d6) psychic damage."}],"legendary_actions":[]},
    {"name": "Death Knight","type":"undead","size":"medium","alignment":"chaotic evil","cr":17,"xp":18000,"ac":20,"ac_type":"plate, shield","hp":"180 (19d8+95)","hp_avg":180,"speed":"30 ft.","str":20,"dex":11,"con":20,"int":12,"wis":16,"cha":18,"skills":None,"saves":"Dex +6, Wis +9, Cha +10","damage_immunities":"necrotic, poison","condition_immunities":"exhaustion, frightened, poisoned","senses":"darkvision 120 ft., passive Perception 13","languages":"Abyssal, Common","environment":["underdark","mountain"],"traits":[{"name":"Magic Resistance","desc":"The death knight has advantage on saving throws against spells and other magical effects."},{"name":"Marshal Undead","desc":"Undead creatures of the death knight's choice within 60 ft. have advantage on saving throws against features that turn undead."},{"name":"Spellcasting","desc":"The death knight is a 19th-level spellcaster. Spell save DC 18, +10 to hit. 1st-5th level spells prepared."}],"actions":[{"name":"Multiattack","desc":"The death knight makes three longsword attacks."},{"name":"Longsword","desc":"Melee Weapon Attack: +11 to hit, reach 5 ft., one target. Hit: 9 (1d8 + 5) slashing damage, or 10 (1d10 + 5) slashing damage if used with two hands, plus 18 (4d8) necrotic damage."},{"name":"Hellfire Orb (1/Day)","desc":"The death knight hurls a magical ball of fire that explodes at a point it can see within 120 ft. Each creature in a 20-foot-radius sphere must make a DC 18 Dexterity saving throw, taking 35 (10d6) fire damage and 35 (10d6) necrotic damage on a failed save, or half as much on a success."}],"legendary_actions":[]},
