    {"name": "Stone Golem","type":"construct","size":"large","alignment":"unaligned","cr":10,"xp":5900,"ac":17,"ac_type":"natural armor","hp":"178 (17d10+85)","hp_avg":178,"speed":"30 ft.","str":22,"dex":9,"con":20,"int":3,"wis":11,"cha":1,"skills":None,"saves":None,"damage_immunities":"poison, psychic; bludgeoning, piercing, and slashing from nonmagical attacks not made with adamantine weapons","condition_immunities":"charmed, exhaustion, frightened, paralyzed, petrified, poisoned","senses":"darkvision 120 ft., passive Perception 10","languages":"understands the languages of its creator but can't speak","environment":["underdark","urban"],"traits":[{"name":"Immutable Form","desc":"The golem is immune to any spell or effect that would alter its form."},{"name":"Magic Resistance","desc":"The golem has advantage on saving throws against spells and other magical effects."},{"name":"Magic Weapons","desc":"The golem's weapon attacks are magical."}],"actions":[{"name":"Multiattack","desc":"The golem makes two slam attacks."},{"name":"Slam","desc":"Melee Weapon Attack: +10 to hit, reach 5 ft., one target. Hit: 19 (3d8 + 6) bludgeoning damage."},{"name":"Slow (Recharge 5-6)","desc":"The golem targets one or more creatures it can see within 10 ft. of it. Each target must make a DC 17 Wisdom saving throw against this magic. On a failed save, a target can't use reactions, its speed is halved, and it can't make more than one attack on its turn."}],"legendary_actions":[]},
